




































import Vue from 'vue';
import QuizGroupCard from '@/components/workspace/QuizGroupCard.vue';
import EmptyHint from '@/components/workspace/EmptyHint.vue';
import ManagerApi from '@/apis/ManagerApi';
import { ManagerEntryInfoModel } from '@/apis/models/ManagerModel';
import { WorkspaceDataModel } from '@/apis/models/WorkspaceModel';
import QuizGroupApi from '@/apis/QuizGroupApi';
import { QuizGroupData, SharedQuizGroup } from '@/apis/models/QuizGroupModel';
import ShareMappingApi from '@/apis/ShareMappingApi';
import Auth from '@/libs/auth';
import { ResourceType } from '@/apis/models/ShareMappingModel';
import SharedObjectCard from '@/components/workspace/SharedObjectCard.vue';

export default Vue.extend({
  components: {
    QuizGroupCard,
    SharedObjectCard,
    EmptyHint,
  },
  data() {
    return {
      quizGroups: [] as QuizGroupData[],
      sharedQuizGroups: [] as SharedQuizGroup[],
    };
  },
  computed: {
    currentWorkspace(): WorkspaceDataModel {
      return this.$store.state.currentWorkspace;
    },
  },
  async mounted() {
    Auth.loginCheck();

    // [Development] temperarily put manager info here
    await ManagerApi.getManagerEntryInfo().then((info: ManagerEntryInfoModel) => {
      this.$store.commit('updateWorkspaceList', info.workspaceList);
      this.$store.commit('changeWorkspace', info.workspaceList[0]);
      this.$store.commit('setUsername', info.username);
    });

    await ShareMappingApi.list(ResourceType.QUIZ_GROUP).then((quizGroups) => {
      this.sharedQuizGroups = quizGroups as SharedQuizGroup[];
    });

    await QuizGroupApi.getQuizGroups(this.currentWorkspace.uuid).then(
      (datalist) => {
        this.quizGroups = datalist;
      },
    );
  },
  methods: {
    async removeGroupCard(index: number) {
      if (index >= 0 && index < this.quizGroups.length) {
        await QuizGroupApi.remove(this.currentWorkspace.uuid, this.quizGroups[index].uuid);
        this.quizGroups.splice(index, 1);
      }
    },
  },
});
